mapper.select:
SELECT c.*, u.nickname as user_name, u.avatar as user_avatar, p.title as post_title FROM forum_comment c LEFT JOIN sys_user u ON c.user_id = u.id LEFT JOIN forum_post p ON c.post_id = p.id
AND c.post_id = #{postId}
AND (c.content LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
AND c.status = #{status}
ORDER BY c.create_time DESC
